design:
Extend InMemoryStorage with async persistence (matches rivets-0gc async trait pattern):

**Async Implementation:**

```rust
impl InMemoryStorage {
    pub async fn load_from_jsonl(path: &Path) -> Result<(Self, Vec<LoadWarning>)> {
        use tokio::fs::File;
        use tokio::io::{AsyncBufReadExt, BufReader};

        let file = BufReader::new(File::open(path).await?);
        let storage = Arc::new(Mutex::new(InMemoryStorageInner::new()));
        let mut warnings = Vec::new();
        let mut lines = file.lines();

        // First pass: import all issues (without dependencies)
        while let Some(line) = lines.next_line().await? {
            match serde_json::from_str::<Issue>(&line) {
                Ok(issue) => {
                    let mut inner = storage.lock().await;
                    let id = issue.id.clone();
                    inner.issues.insert(id.clone(), issue);
                    let node = inner.graph.add_node(id.clone());
                    inner.node_map.insert(id, node);
                }
                Err(e) => {
                    warnings.push(LoadWarning::MalformedJson { line, error: e });
                    log::warn!("Skipping malformed JSON: {}", e);
                }
            }
        }

        // Second pass: add dependency edges with orphan/cycle detection
        let mut inner = storage.lock().await;
        for issue in inner.issues.values() {
            for dep in &issue.dependencies {
                // Check if dependency target exists
                if !inner.issues.contains_key(&dep.depends_on_id) {
                    warnings.push(LoadWarning::OrphanedDependency {
                        from: issue.id.clone(),
                        to: dep.depends_on_id.clone(),
                    });
                    log::warn!("Skipping orphaned dependency: {} -> {}", 
                              issue.id, dep.depends_on_id);
                    continue;
                }

                // Check for cycles before adding edge
                if inner.has_cycle_internal(&issue.id, &dep.depends_on_id)? {
                    warnings.push(LoadWarning::CircularDependency {
                        from: issue.id.clone(),
                        to: dep.depends_on_id.clone(),
                    });
                    log::warn!("Skipping circular dependency: {} -> {}", 
                              issue.id, dep.depends_on_id);
                    continue;
                }

                // Add edge to graph
                inner.add_dependency_edge_internal(dep)?;
            }
        }

        Ok((storage, warnings))
    }

    pub async fn save_to_jsonl(&self, path: &Path) -> Result<()> {
        use tokio::fs::File;
        use tokio::io::{AsyncWriteExt, BufWriter};

        // Atomic write: temp file + rename
        let temp_path = path.with_extension("tmp");
        let file = BufWriter::new(File::create(&temp_path).await?);

        let inner = self.lock().await;
        for issue in inner.issues.values() {
            let json = serde_json::to_string(issue)?;
            file.write_all(json.as_bytes()).await?;
            file.write_all(b"\n").await?;  // Newline-delimited
        }
        file.flush().await?;

        // Atomic rename
        tokio::fs::rename(&temp_path, path).await?;
        Ok(())
    }
}
```

**Error Handling:**
- Malformed JSON: Skip line, log warning, continue loading
- Orphaned dependencies: Skip edge, log warning, import issue without that dependency
- Circular dependencies: Skip edge, log warning, prevent cycle creation
- Returns (Storage, Vec<LoadWarning>) to communicate warnings to caller

**File format**: Standard JSONL (newline-delimited JSON)
**Atomicity**: Write to temp file, then rename (atomic on POSIX systems)
**Dependencies**: tokio with fs feature for async file I/O

