design:
```rust
use std::marker::PhantomData;

pub struct JsonlQuery<T> {
    predicates: Vec<Box<dyn Fn(&T) -> bool + Send + Sync>>,
    _phantom: PhantomData<T>,
}

impl<T> JsonlQuery<T>
where
    T: DeserializeOwned + 'static,
{
    pub fn new() -> Self {
        Self {
            predicates: Vec::new(),
            _phantom: PhantomData,
        }
    }

    pub fn filter<F>(mut self, predicate: F) -> Self
    where
        F: Fn(&T) -> bool + Send + Sync + 'static,
    {
        self.predicates.push(Box::new(predicate));
        self
    }

    fn matches(&self, value: &T) -> bool {
        self.predicates.iter().all(|pred| pred(value))
    }
}
```

```rust
use serde::de::DeserializeOwned;
use tokio::io::AsyncBufReadExt;

impl<R: AsyncRead + Unpin> JsonlReader<R> {
    pub async fn read_line<T: DeserializeOwned>(&mut self) -> Result<Option<T>> {
        let mut line = String::new();
        let bytes_read = self.reader.read_line(&mut line).await?;

        if bytes_read == 0 {
            return Ok(None); // EOF
        }

        self.line_number += 1;

        let trimmed = line.trim();
        if trimmed.is_empty() {
            // Skip empty lines, read next
            return self.read_line().await;
        }

        let value: T = serde_json::from_str(trimmed)
            .map_err(|e| Error::Json(e))?;

        Ok(Some(value))
    }
}
```

