fn index(&mut self) -> Result<IndexStats> {
    let files = self.discover_files()?;
    let mut pending: Vec<PendingDependency> = Vec::new();

    // First pass: index all files, queue failed dependencies
    for file in &files {
        self.index_file_atomic(file, &mut pending)?;
