impl Tethys {
    /// Returns the per-file crate_root for use by the resolver and dep-graph
    /// computation. Falls back to the file's parent directory as a sentinel
    /// when the file is outside any known crate (workspace-root example/bench
    /// dirs).
    fn crate_root_for_file(&self, file: &Path, caller: &'static str) -> PathBuf {
        if let Some(crate_info) = crate::cargo::get_crate_for_file(file, &self.crates) {
